create table dirkspzm32.s_rcv_uml_auftrag (
    sid              varchar2(2 char) not null enable,
    firma_nr         number(6, 0) not null enable,
    erstellt_datum   date not null enable,
    auftrnr          varchar2(20 char) not null enable,
    artikel          varchar2(30 char),
    charge           varchar2(60 char),
    lte_id           varchar2(20 char),
    umldat           date,
    quell_lgr_ort    number(*, 5),
    qiuell_lgr_platz varchar2(30 char),
    ziel_lgr_ort     number(*, 5),
    ziel_lgr_platz   varchar2(30 char),
    ziel_ort_bez     varchar2(30 char)
);


